INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1084", 7, 5, 9, 1, 1, 12300152, 3001, 0, 4.19, 2, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", 3);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1085", 1, 5, 9, 1, 1, 12300153, 3001, 0, 0.0, 2, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", 3);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1086", 3, 5, 9, 1, 1, 12300154, 3001, 0, 2.63, 2, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", 3);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1087", 3, 1, 4, 1, 1, 12300155, 3001, 0, 5.53, 2, "あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか", 1);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1088", 3, 1, 4, 1, 3, 12300156, 3001, 9, 0.01, 2, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", 1);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1089", 3, 1, 4, 1, 1, 12300157, 3001, 3, 4.15, 2, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", 1);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1090", 9, 1, 4, 1, 9, 12300158, 3001, 9, 0.01, 2, "ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？", 2);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1091", 3, 1, 4, 1, 1, 12300159, 3001, 0, 5.37, 2, "あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！", 2);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1092", 3, 1, 4, 1, 1, 12300160, 3001, 0, 1.44, 2, "なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～", 2);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1093", 3, 1, 4, 1, 3, 12300161, 3001, 0, 0.0, 2, "んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？", 3);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1094", 3, 1, 4, 1, 9, 12300162, 3001, 3, 2.91, 2, "…あんまり点数取れなかったわね\nこれはあたしにも難しい問題だし\nそう落ち込まなくても大丈夫！\n次頑張りましょ！", 3);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1095", 5, 1, 4, 1, 1, 12300163, 3001, 0, 2.61, 2, "ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！", 3);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1096", 4, 0, 0, 1, 2, 12300164, 3001, 1, 3.63, 2, "ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！", 1);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1097", 6, 0, 0, 1, 2, 12300165, 3001, 1, 4.16, 2, "はあ…自分で何点取ったか\n分かってるわよね～…？\n０点よ０点！　舐めてんの！？", 1);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1098", 3, 0, 0, 1, 3, 12300166, 3001, 6, 0.01, 2, "うう～頭痛い…\nあんたのせいよ！\nなに０点って！\nはあ、このままじゃ赤点よ～…", 1);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1099", 6, 0, 0, 1, 2, 12300167, 3001, 0, 5.75, 2, "ねえ、あんた本気でやったの？\nまさか適当にやるわけないわよね\n…分かった、\nもう一回チャレンジするのよ！", 2);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1100", 4, 0, 0, 1, 2, 12300168, 3001, 1, 5.64, 2, "あ…あんた、０点よ０点…！\nあたしの教え方が悪かった…？\n…燃えてきたわ！\n絶対あんたの学力上げてやる！", 2);
