INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES ("vo_minigame_1012_result_1102", 5, 0, 0, 1, 3, 12300170, 3001, 1, 5.32, 2, "あらら…０点よ\nま、難しい問題だしね…\n…つっても０点は無いわ！\n一問くらい正解しなさいよ！", 3);
